    compatibilityDate: '2026-03-07',
    ssr: false,
    devtools: {enabled: true},
    css: [
        '~/assets/css/main.css',
        '~/assets/css/markdown.css',
    ],
    icon: {
        provider: 'none',
        clientBundle: {
            icons:[
                'lucide:chevrons-left',
                'lucide:chevron-left',
                'lucide:chevrons-right',
                'lucide:chevron-right',
            ],
            // scan all components in the project and include icons
